import React, { useState, useEffect, useRef } from 'react';

const theme = {
  bg: '#0a0a0a',
  surface: '#111111',
  surfaceAlt: '#1a1a1a',
  border: '#2a2a2a',
  text: '#fafafa',
  muted: '#a1a1aa',
  dim: '#71717a',
  primary: '#8b5cf6',
  blue: '#38bdf8',
  yellow: '#fbbf24',
  green: '#a3e635',
  orange: '#fb923c',
  font: "'JetBrains Mono', monospace",
};

// Two parameters with very different gradient scales:
// param1: steep loss L1 = 4*(p - 0)^2, grad = 8*p  (large gradients)
// param2: flat  loss L2 = 0.1*(p - 0)^2, grad = 0.2*p (small gradients)
// Both start at 3.0. Adagrad adapts LR differently for each!

const INIT_P = 3.0;
const INIT_G = 0.0;
const EPS = 1e-8;

function grad1(p) { return 8 * p; }
function grad2(p) { return 0.2 * p; }
function loss1(p) { return 4 * p * p; }
function loss2(p) { return 0.1 * p * p; }

function adagradStep(p, G, g, lr) {
  const newG = G + g * g;
  const effLR = lr / (Math.sqrt(newG) + EPS);
  const newP = p - effLR * g;
  return { p: newP, G: newG, effLR };
}

function fixedStep(p, g, lr) {
  return p - lr * g;
}

export default function App() {
  const [lr, setLr] = useState(0.3);
  const [history, setHistory] = useState([
    { p1: INIT_P, p2: INIT_P, G1: INIT_G, G2: INIT_G, effLR1: 0.3, effLR2: 0.3 }
  ]);
  const [fixedHist, setFixedHist] = useState([
    { p1: INIT_P, p2: INIT_P }
  ]);
  const [playing, setPlaying] = useState(false);
  const intervalRef = useRef(null);

  const cur = history[history.length - 1];
  const step = history.length - 1;
  const converged = Math.abs(cur.p1) < 0.05 && Math.abs(cur.p2) < 0.05;

  function doStep(hist, fhist, lrVal) {
    const last = hist[hist.length - 1];
    const g1 = grad1(last.p1);
    const g2 = grad2(last.p2);
    const r1 = adagradStep(last.p1, last.G1, g1, lrVal);
    const r2 = adagradStep(last.p2, last.G2, g2, lrVal);
    const flast = fhist[fhist.length - 1];
    const fp1 = fixedStep(flast.p1, grad1(flast.p1), lrVal);
    const fp2 = fixedStep(flast.p2, grad2(flast.p2), lrVal);
    const newHist = [...hist, { p1: r1.p, p2: r2.p, G1: r1.G, G2: r2.G, effLR1: r1.effLR, effLR2: r2.effLR }];
    const newFixed = [...fhist, { p1: fp1, p2: fp2 }];
    return { newHist, newFixed };
  }

  function stepForward() {
    if (converged || step >= 30) return;
    const { newHist, newFixed } = doStep(history, fixedHist, lr);
    setHistory(newHist);
    setFixedHist(newFixed);
  }

  useEffect(() => {
    if (playing) {
      intervalRef.current = setInterval(() => {
        setHistory(prev => {
          setFixedHist(prevF => {
            if (prev.length > 30) { setPlaying(false); return prevF; }
            const last = prev[prev.length - 1];
            if (Math.abs(last.p1) < 0.05 && Math.abs(last.p2) < 0.05) { setPlaying(false); return prevF; }
            const { newHist, newFixed } = doStep(prev, prevF, lr);
            setTimeout(() => setHistory(newHist), 0);
            return newFixed;
          });
          return prev;
        });
      }, 700);
    }
    return () => clearInterval(intervalRef.current);
  }, [playing, lr]);

  // Better approach - use a ref for history to avoid closure issues
  const histRef = useRef(history);
  const fixedRef = useRef(fixedHist);
  histRef.current = history;
  fixedRef.current = fixedHist;

  useEffect(() => {
    if (playing) {
      clearInterval(intervalRef.current);
      intervalRef.current = setInterval(() => {
        const prev = histRef.current;
        const prevF = fixedRef.current;
        const last = prev[prev.length - 1];
        if (prev.length > 30 || (Math.abs(last.p1) < 0.05 && Math.abs(last.p2) < 0.05)) {
          setPlaying(false);
          clearInterval(intervalRef.current);
          return;
        }
        const { newHist, newFixed } = doStep(prev, prevF, lr);
        setHistory(newHist);
        setFixedHist(newFixed);
      }, 650);
    } else {
      clearInterval(intervalRef.current);
    }
    return () => clearInterval(intervalRef.current);
  }, [playing, lr]);

  function reset() {
    setPlaying(false);
    setHistory([{ p1: INIT_P, p2: INIT_P, G1: INIT_G, G2: INIT_G, effLR1: lr, effLR2: lr }]);
    setFixedHist([{ p1: INIT_P, p2: INIT_P }]);
  }

  // SVG for one parameter's loss curve
  const W = 252, H = 130, px = 20, py = 14;
  const iW = W - 2 * px, iH = H - 2 * py;
  const pMin = -0.5, pMax = 3.5;
  const toX = (p) => px + (p - pMin) / (pMax - pMin) * iW;
  const toY1 = (p) => py + iH - Math.min(iH, loss1(p) / 36 * iH);
  const toY2 = (p) => py + iH - Math.min(iH, loss2(p) / 0.9 * iH);

  function makeCurve(toY) {
    const pts = [];
    for (let p = pMin; p <= pMax; p += 0.08) pts.push(`${toX(p).toFixed(1)},${toY(p).toFixed(1)}`);
    return 'M ' + pts.join(' L ');
  }

  function makePath(hist, toY, key) {
    return hist.map(h => `${toX(h[key]).toFixed(1)},${toY(h[key]).toFixed(1)}`).join(' ');
  }

  const maxG = Math.max(cur.G1, cur.G2, 1);

  // Effective LR as % of original
  const effPct1 = step === 0 ? 100 : (cur.effLR1 / lr * 100);
  const effPct2 = step === 0 ? 100 : (cur.effLR2 / lr * 100);

  const insightText = () => {
    if (step === 0) return 'Press Play or Step Forward. Watch how Adagrad gives EACH parameter its own adaptive learning rate.';
    if (converged) return `Converged! Steep param got effLR=${cur.effLR1.toFixed(4)} (${effPct1.toFixed(1)}% of original). Flat param kept effLR=${cur.effLR2.toFixed(4)} (${effPct2.toFixed(1)}%). Same LR input, totally different adaptation!'`;
    return `Steep param: G=${cur.G1.toFixed(1)} -> effLR down to ${effPct1.toFixed(1)}% of original. Flat param: G=${cur.G2.toFixed(3)} -> effLR still at ${effPct2.toFixed(1)}%. Adagrad punishes large-gradient params more!`;
  };

  return (
    <div style={{ fontFamily: theme.font, background: theme.bg, color: theme.text, minHeight: '100vh', padding: '14px', maxWidth: '600px', margin: '0 auto', boxSizing: 'border-box' }}>

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
        <div>
          <div style={{ fontSize: '17px', fontWeight: '700' }}>Adagrad Optimizer</div>
          <div style={{ fontSize: '10px', color: theme.muted, marginTop: '1px' }}>Adaptive gradients — each param learns at its own pace</div>
        </div>
        <div style={{ display: 'flex', gap: '6px' }}>
          <button onClick={() => setPlaying(p => !p)}
            style={{ padding: '5px 13px', background: playing ? theme.surfaceAlt : theme.primary, border: 'none', borderRadius: '6px', color: theme.text, cursor: 'pointer', fontSize: '11px', fontFamily: theme.font, fontWeight: '600' }}>
            {playing ? 'Pause' : 'Play'}
          </button>
          <button onClick={reset}
            style={{ padding: '5px 10px', background: theme.surfaceAlt, border: `1px solid ${theme.border}`, borderRadius: '6px', color: theme.muted, cursor: 'pointer', fontSize: '11px', fontFamily: theme.font }}>
            Reset
          </button>
        </div>
      </div>

      {/* LR Slider */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '10px', background: theme.surface, borderRadius: '8px', padding: '8px 12px', border: `1px solid ${theme.border}` }}>
        <span style={{ fontSize: '10px', color: theme.muted, minWidth: '80px' }}>Learning Rate</span>
        <input type="range" min="0.05" max="1.0" step="0.05" value={lr}
          onChange={e => { setLr(parseFloat(e.target.value)); reset(); }}
          style={{ flex: 1, accentColor: theme.primary }} />
        <span style={{ fontSize: '13px', fontWeight: '700', color: theme.yellow, minWidth: '36px' }}>{lr.toFixed(2)}</span>
        <button onClick={stepForward} disabled={converged || step >= 30}
          style={{ padding: '4px 12px', background: theme.surfaceAlt, border: `1px solid ${theme.primary}`, borderRadius: '5px', color: theme.primary, cursor: converged ? 'not-allowed' : 'pointer', fontSize: '10px', fontFamily: theme.font, opacity: (converged || step >= 30) ? 0.4 : 1 }}>
          Step
        </button>
      </div>

      {/* Two loss curves */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '10px' }}>

        {/* Param 1 - Steep */}
        <div style={{ background: theme.surface, borderRadius: '8px', border: `1px solid ${theme.border}`, padding: '4px' }}>
          <div style={{ textAlign: 'center', fontSize: '9px', color: theme.muted, paddingTop: '4px' }}>
            Param 1 — <span style={{ color: theme.orange }}>STEEP</span> loss (large grads)
          </div>
          <svg width="100%" viewBox={`0 0 ${W} ${H}`} style={{ display: 'block' }}>
            <line x1={px} x2={W - px} y1={py + iH} y2={py + iH} stroke={theme.border} strokeWidth="1" />
            <line x1={toX(0)} x2={toX(0)} y1={py} y2={py + iH} stroke={theme.dim} strokeWidth="0.8" strokeDasharray="3,3" />
            <text x={toX(0)} y={py - 2} textAnchor="middle" fill={theme.green} fontSize="8">min</text>

            {/* Fixed LR ghost */}
            {step > 0 && (
              <polyline points={makePath(fixedHist, toY1, 'p1')} fill="none" stroke={theme.orange} strokeWidth="1.5" strokeDasharray="3,3" opacity="0.45" />
            )}
            {step > 0 && (() => { const lp = fixedHist[fixedHist.length-1]; return <circle cx={toX(lp.p1)} cy={toY1(lp.p1)} r="4" fill={theme.orange} opacity="0.5" />; })()}

            {/* Loss curve */}
            <path d={makeCurve(toY1)} fill="none" stroke={theme.blue} strokeWidth="1.8" opacity="0.6" />

            {/* Adagrad path */}
            {history.length > 1 && (
              <polyline points={makePath(history, toY1, 'p1')} fill="none" stroke={theme.primary} strokeWidth="2" opacity="0.8" />
            )}
            {history.map((h, i) => (
              <circle key={i} cx={toX(h.p1)} cy={toY1(h.p1)} r={i === history.length - 1 ? 6 : 2.5}
                fill={i === history.length - 1 ? theme.primary : theme.primary} opacity={i === history.length - 1 ? 1 : 0.35} />
            ))}

            <text x={px} y={py + iH + 12} fill={theme.dim} fontSize="8">p={INIT_P}</text>
            <text x={toX(0) - 4} y={py + iH + 12} fill={theme.green} fontSize="8">0</text>
          </svg>
        </div>

        {/* Param 2 - Flat */}
        <div style={{ background: theme.surface, borderRadius: '8px', border: `1px solid ${theme.border}`, padding: '4px' }}>
          <div style={{ textAlign: 'center', fontSize: '9px', color: theme.muted, paddingTop: '4px' }}>
            Param 2 — <span style={{ color: theme.blue }}>FLAT</span> loss (small grads)
          </div>
          <svg width="100%" viewBox={`0 0 ${W} ${H}`} style={{ display: 'block' }}>
            <line x1={px} x2={W - px} y1={py + iH} y2={py + iH} stroke={theme.border} strokeWidth="1" />
            <line x1={toX(0)} x2={toX(0)} y1={py} y2={py + iH} stroke={theme.dim} strokeWidth="0.8" strokeDasharray="3,3" />
            <text x={toX(0)} y={py - 2} textAnchor="middle" fill={theme.green} fontSize="8">min</text>

            {step > 0 && (
              <polyline points={makePath(fixedHist, toY2, 'p2')} fill="none" stroke={theme.orange} strokeWidth="1.5" strokeDasharray="3,3" opacity="0.45" />
            )}
            {step > 0 && (() => { const lp = fixedHist[fixedHist.length-1]; return <circle cx={toX(lp.p2)} cy={toY2(lp.p2)} r="4" fill={theme.orange} opacity="0.5" />; })()}

            <path d={makeCurve(toY2)} fill="none" stroke={theme.blue} strokeWidth="1.8" opacity="0.6" />

            {history.length > 1 && (
              <polyline points={makePath(history, toY2, 'p2')} fill="none" stroke={theme.primary} strokeWidth="2" opacity="0.8" />
            )}
            {history.map((h, i) => (
              <circle key={i} cx={toX(h.p2)} cy={toY2(h.p2)} r={i === history.length - 1 ? 6 : 2.5}
                fill={i === history.length - 1 ? theme.primary : theme.primary} opacity={i === history.length - 1 ? 1 : 0.35} />
            ))}

            <text x={px} y={py + iH + 12} fill={theme.dim} fontSize="8">p={INIT_P}</text>
            <text x={toX(0) - 4} y={py + iH + 12} fill={theme.green} fontSize="8">0</text>
          </svg>
        </div>
      </div>

      {/* Legend */}
      <div style={{ display: 'flex', gap: '16px', justifyContent: 'center', marginBottom: '10px', fontSize: '10px', color: theme.muted }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
          <svg width="18" height="6"><line x1="0" y1="3" x2="18" y2="3" stroke={theme.primary} strokeWidth="2.5" /></svg>
          Adagrad
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
          <svg width="18" height="6"><line x1="0" y1="3" x2="18" y2="3" stroke={theme.orange} strokeWidth="1.5" strokeDasharray="3,3" opacity="0.7" /></svg>
          Fixed LR
        </div>
      </div>

      {/* Adaptive LR bars - THE KEY INSIGHT */}
      <div style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: '8px', padding: '12px', marginBottom: '10px' }}>
        <div style={{ fontSize: '10px', color: theme.muted, marginBottom: '10px', textAlign: 'center' }}>
          Effective LR = <span style={{ color: theme.yellow }}>lr</span> / (sqrt(<span style={{ color: theme.yellow }}>G</span>) + eps)&nbsp;&nbsp;— watch how each param adapts
        </div>

        {/* Param 1 row */}
        <div style={{ marginBottom: '8px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '3px', fontSize: '10px' }}>
            <span style={{ color: theme.orange }}>Param 1 (steep, large grads)</span>
            <span style={{ color: theme.dim }}>G = <span style={{ color: theme.yellow }}>{cur.G1.toFixed(1)}</span>&nbsp;&nbsp;effLR = <span style={{ color: theme.green }}>{step === 0 ? lr.toFixed(4) : cur.effLR1.toFixed(5)}</span></span>
          </div>
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
            <span style={{ fontSize: '9px', color: theme.dim, width: '20px', textAlign: 'right' }}>G</span>
            <div style={{ flex: 1, height: '8px', background: theme.surfaceAlt, borderRadius: '4px', overflow: 'hidden' }}>
              <div style={{ width: `${Math.min(100, (cur.G1 / Math.max(cur.G1, cur.G2, 1)) * 100)}%`, height: '100%', background: theme.orange, borderRadius: '4px', transition: 'width 0.4s ease' }} />
            </div>
          </div>
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center', marginTop: '3px' }}>
            <span style={{ fontSize: '9px', color: theme.dim, width: '20px', textAlign: 'right' }}>eLR</span>
            <div style={{ flex: 1, height: '8px', background: theme.surfaceAlt, borderRadius: '4px', overflow: 'hidden' }}>
              <div style={{ width: `${Math.min(100, effPct1)}%`, height: '100%', background: theme.green, borderRadius: '4px', transition: 'width 0.4s ease' }} />
            </div>
            <span style={{ fontSize: '9px', color: theme.green, width: '32px' }}>{effPct1.toFixed(0)}%</span>
          </div>
        </div>

        {/* Param 2 row */}
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '3px', fontSize: '10px' }}>
            <span style={{ color: theme.blue }}>Param 2 (flat, small grads)</span>
            <span style={{ color: theme.dim }}>G = <span style={{ color: theme.yellow }}>{cur.G2.toFixed(4)}</span>&nbsp;&nbsp;effLR = <span style={{ color: theme.green }}>{step === 0 ? lr.toFixed(4) : cur.effLR2.toFixed(4)}</span></span>
          </div>
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
            <span style={{ fontSize: '9px', color: theme.dim, width: '20px', textAlign: 'right' }}>G</span>
            <div style={{ flex: 1, height: '8px', background: theme.surfaceAlt, borderRadius: '4px', overflow: 'hidden' }}>
              <div style={{ width: `${Math.min(100, (cur.G2 / Math.max(cur.G1, cur.G2, 1)) * 100)}%`, height: '100%', background: theme.blue, borderRadius: '4px', transition: 'width 0.4s ease' }} />
            </div>
          </div>
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center', marginTop: '3px' }}>
            <span style={{ fontSize: '9px', color: theme.dim, width: '20px', textAlign: 'right' }}>eLR</span>
            <div style={{ flex: 1, height: '8px', background: theme.surfaceAlt, borderRadius: '4px', overflow: 'hidden' }}>
              <div style={{ width: `${Math.min(100, effPct2)}%`, height: '100%', background: theme.green, borderRadius: '4px', transition: 'width 0.4s ease' }} />
            </div>
            <span style={{ fontSize: '9px', color: theme.green, width: '32px' }}>{effPct2.toFixed(0)}%</span>
          </div>
        </div>
      </div>

      {/* Step counter row */}
      <div style={{ display: 'flex', gap: '6px', marginBottom: '10px' }}>
        {[
          { label: 'Steps', val: step, c: theme.muted },
          { label: 'Param 1', val: cur.p1.toFixed(3), c: theme.orange },
          { label: 'Param 2', val: cur.p2.toFixed(3), c: theme.blue },
        ].map(({ label, val, c }) => (
          <div key={label} style={{ flex: 1, background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: '6px', padding: '6px', textAlign: 'center' }}>
            <div style={{ fontSize: '9px', color: theme.dim, marginBottom: '3px' }}>{label}</div>
            <div style={{ fontSize: '12px', fontWeight: '700', color: c }}>{val}</div>
          </div>
        ))}
      </div>

      {/* Insight */}
      <div style={{ padding: '10px 14px', background: theme.surfaceAlt, borderRadius: '8px', borderLeft: `3px solid ${theme.primary}`, fontSize: '10px', color: theme.muted, lineHeight: '1.65' }}>
        <span style={{ color: theme.primary, fontWeight: '700' }}>Key Insight: </span>
        {insightText()}
      </div>
    </div>
  );
}
